def inventory(skills):
    result = {"eaten": [], "survived": [], "advantage": []}
    category_to_key = {
        "eaten_by_ai": "eaten",
        "survived_ai": "survived",
        "new_advantage": "advantage",
    }
    for skill in skills:
        key = category_to_key[skill["category"]]
        result[key].append(skill["name"])
    return result

print(inventory(skills))

