def classify_framings(framings):
    correct_count = sum(1 for f in framings if f["correct"])
    wrong_statements = [f["statement"] for f in framings if not f["correct"]]
    return (correct_count, wrong_statements)

correct_count, wrong_statements = classify_framings(framings)
print(f"correct: {correct_count}")
print("wrong:")
