learners = [
    {"name": "Maya",  "background": "engineer",   "hours_per_week": 20},
    {"name": "Devon", "background": "copywriter", "hours_per_week": 16},
    {"name": "Priya", "background": "cs_rep",     "hours_per_week": 8},
    {"name": "Jules", "background": "designer",   "hours_per_week": 14},
    {"name": "Sam",   "background": "paralegal",  "hours_per_week": 10},
]

def _plan(background, hours):
    if background == "engineer":
        starting_chapter = 4
        weekly_chapters = max(2, hours // 5)
    elif background == "designer":
        starting_chapter = 1
        weekly_chapters = max(1, hours // 7)
    else:
        starting_chapter = 1
        weekly_chapters = max(1, hours // 8)
    target = min(30, starting_chapter + 4 * weekly_chapters - 1)
    return starting_chapter, target

def route_learners(learners):
    routes = []
    by_background = {}
    for learner in learners:
        start, target = _plan(learner["background"], learner["hours_per_week"])
        routes.append((learner["name"], start, target))
        by_background[learner["background"]] = by_background.get(learner["background"], 0) + 1
    return {"routes": routes, "by_background": by_background}

result = route_learners(learners)
print("routes:")
for r in result["routes"]:
    print(r)
print(f"by_background: {result['by_background']}")
